@dataclass
class LLMResponse:
    """LLM 提供者的响应"""
    content: str | None
    tool_calls: list[ToolCallRequest] = field(default_factory=list)
    finish_reason: str = "stop"
    usage: dict[str, int] = field(default_factory=dict)
    reasoning_content: str | None = None  # Kimi, DeepSeek-R1 等
    thinking_blocks: list[dict] | None = None  # Anthropic extended thinking

    @property
    def has_tool_calls(self) -> bool:
        """检查响应中是否包含工具调用。"""
        return len(self.tool_calls) > 0


@dataclass

class TestLLMResponse:
    def test_no_tool_calls(self):
        resp = LLMResponse(content="hello")
        assert resp.content == "hello"
        assert resp.has_tool_calls is False
        assert resp.tool_calls == []
        assert resp.finish_reason == "stop"

    def test_with_tool_calls(self):
        tc = ToolCallRequest(id="c1", name="read_file", arguments={"path": "a"})
        resp = LLMResponse(content=None, tool_calls=[tc])
        assert resp.has_tool_calls is True
        assert len(resp.tool_calls) == 1
        assert resp.tool_calls[0].name == "read_file"

    def test_none_content(self):
        resp = LLMResponse(content=None)
        assert resp.content is None

    def test_usage_defaults(self):
        resp = LLMResponse(content="x")
        assert resp.usage == {}

    def test_reasoning_content(self):
        resp = LLMResponse(content="answer", reasoning_content="let me think...")
        assert resp.reasoning_content == "let me think..."


